// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MOD 1000000007
int dp[2000001];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        dp[0] = 1;
        for (int i = 0; i < N; i++) {
            int curr = 1 << A[i];
            for (int j = K; j >= curr; j--) {
                dp[j] = (dp[j] + dp[j - curr]) % MOD;
            }
        }
        printf("%d\n", dp[K]);
    }
    return 0;
}

